                        .invoke(config, "processors");
                    if (processors != null) {
                        Object[] children = (Object[]) processors.getClass()
                            .getMethod("getChildren").invoke(processors);
                        return (Set<String>) (Set<?>) java.util.Arrays.stream(children)
                            .map(child -> {
                                try {
                                    return (String) child.getClass()
