@Override
@SuppressWarnings("unchecked")
public Set<String> collectUsedClassesFromProcessors() {
    getLog().debug("# collectUsedClassesFromProcessors()");
    Optional<org.apache.maven.model.Plugin> pluginOpt = Optional.ofNullable(project.getPlugin("org.bsc.maven:maven-processor-plugin"));
    if (!pluginOpt.isPresent()) {
        return java.util.Collections.emptySet();
    }

    org.apache.maven.model.Plugin plugin = pluginOpt.get();
    org.apache.maven.model.PluginExecution exec = plugin.getExecutionsAsMap().get("process");
    if (exec == null) {
        return java.util.Collections.emptySet();
    }

    Object config = exec.getConfiguration();
    if (config == null) {
        return java.util.Collections.emptySet();
    }

    try {
        Object processors = config.getClass().getMethod("getChild", String.class)
            .invoke(config, "processors");
        if (processors != null) {
            Object[] children = (Object[]) processors.getClass()
                .getMethod("getChildren").invoke(processors);
            Set<String> result = new java.util.HashSet<>();
            for (Object child : children) {
                try {
                    String value = (String) child.getClass()
                        .getMethod("getValue").invoke(child);
                    if (value != null) {
                        result.add(value);
                    }
                } catch (Exception e) {
                    // Ignore individual child errors
                }
            }
            return result;
        }
    } catch (Exception e) {
        // Ignore reflection errors
    }
    return java.util.Collections.emptySet();
}

